#!/usr/bin/perl

use strict;
use warnings;
use CGI;
use CGI::Carp qw(fatalsToBrowser);

my $q = CGI->new;

my $log_dir = '/var/log'; # Define your log directory here

print $q->header;
print $q->start_html('Log File Viewer');
print $q->h1('Log File Viewer');

my $filename = $q->param('logfile');

if (!$filename) {
    print $q->p('Please provide a logfile parameter. Example: ?logfile=syslog');
} else {
    # Basic sanitization: ensure filename doesn't contain path separators
    if ($filename =~ m![/\\!] || $filename =~ m!\.\.!) {
        print $q->p('Invalid filename provided.');
    } else {
        my $filepath = "$log_dir/$filename";

        if (-f $filepath && -r $filepath) {
            print $q->pre;
            open(my $fh, '<', $filepath) or die "Cannot open $filepath: $!";
            while (my $line = <$fh>) {
                print CGI::escapeHTML($line);
            }
            close($fh);
            print $q->end_pre;
        } else {
            print $q->p("Log file '$filename' not found or not readable in '$log_dir'.");
        }
    }
}

print $q->end_html;